operaciones = {
    '+': lambda a, b: a + b,
    '-': lambda a, b: a - b,
    '*': lambda a, b: a * b,
    '/': lambda a, b: a / b,
}
a = float(input('Ingresa el primer número: '))
operador = input('Ingresa el operador (+, -, *, /): ')
b = float(input('Ingresa el segundo número: '))
if operador not in operaciones:
    print('Operador no válido.')
elif operador == '/' and b == 0:
    print('Error: división por cero.')
else:
    resultado = operaciones[operador](a, b)
    print(f'Resultado: {a} {operador} {b} = {resultado}')

frase = input('Ingresa una frase: ').lower()
frecuencia = {}
for letra in frase:
    if letra != ' ':
        frecuencia[letra] = frecuencia.get(letra, 0) + 1
for letra, count in sorted(frecuencia.items(), key=lambda x: x[1], reverse=True):
    print(f'{letra}: {count}')

import random
secreto = random.randint(1, 100)
intentos = 0
while True:
    intento = int(input('Adivina el número (1-100): '))
    intentos += 1
    if intento < secreto:
        print('Demasiado bajo.')
    elif intento > secreto:
        print('Demasiado alto.')
    else:
        print(f'¡Correcto! Lo adivinaste en {intentos} intento(s).')
        break

agenda = {}
while True:
    opcion = input('1-Agregar 2-Buscar 3-Listar 4-Salir: ')
    if opcion == '1':
        nombre = input('Nombre: ')
        telefono = input('Teléfono: ')
        agenda[nombre] = telefono
        print('Contacto agregado.')
    elif opcion == '2':
        nombre = input('Nombre a buscar: ')
        if nombre in agenda:
            print(f'Teléfono: {agenda[nombre]}')
        else:
            print('Contacto no encontrado.')
    elif opcion == '3':
        for nombre, tel in agenda.items():
            print(f'{nombre}: {tel}')
    elif opcion == '4':
        print('Saliendo.')
        break
    else:
        print('Opción no válida.')

clave = input('Ingresa una contraseña: ')
reglas = {
    'Al menos 8 caracteres': len(clave) >= 8,
    'Una mayúscula': any(c.isupper() for c in clave),
    'Una minúscula': any(c.islower() for c in clave),
    'Un dígito': any(c.isdigit() for c in clave),
}
for regla, cumple in reglas.items():
    estado = 'OK' if cumple else 'X'
    print(f'[{estado}] {regla}')
if all(reglas.values()):
    print('Contraseña válida.')
else:
    print('Contraseña no válida.')

def suma_total(*args):
    return sum(args)

n = int(input('¿Cuántos números quieres sumar? '))
numeros = []
for i in range(n):
    num = float(input(f'Número {i+1}: '))
    numeros.append(num)
total = suma_total(*numeros)
print(f'La suma de {n} número(s) es: {total}')

texto = input('Ingresa un párrafo: ').lower()
for ch in '.,!?;:':
    texto = texto.replace(ch, '')
palabras = texto.split()
frecuencia = {}
for p in palabras:
    frecuencia[p] = frecuencia.get(p, 0) + 1
top5 = sorted(frecuencia.items(), key=lambda x: x[1], reverse=True)[:5]
print('Top 5 palabras:')
for palabra, count in top5:
    print(f'  {palabra}: {count}')

inventario = []
while True:
    opcion = input('1-Agregar 2-Ver inventario 3-Stock bajo 4-Salir: ')
    if opcion == '1':
        nombre = input('Nombre del producto: ')
        stock = int(input('Stock inicial: '))
        inventario.append({'nombre': nombre, 'stock': stock})
        print('Producto agregado.')
    elif opcion == '2':
        ordenado = sorted(inventario, key=lambda p: p['stock'], reverse=True)
        for p in ordenado:
            print(f"{p['nombre']}: {p['stock']} unidades")
    elif opcion == '3':
        bajos = [p for p in inventario if p['stock'] < 5]
        if bajos:
            for p in bajos:
                print(f"Stock bajo: {p['nombre']} ({p['stock']} unidades)")
        else:
            print('Sin productos con stock bajo.')
    elif opcion == '4':
        print('Saliendo.')
        break
    else:
        print('Opción no válida.')

n = int(input(f'Ingresa un número entre 2 y 10: '))
if n < 2 or n > 10:
    print('Número fuera de rango.')
else:
    cabecera = '   ' + ' '.join(f'{j:4}' for j in range(1, n + 1))
    print(cabecera)
    for i in range(1, n + 1):
        fila = f'{i:2} |' + ' '.join(f'{i*j:4}' for j in range(1, n + 1))
